// getCanonicalRequest generate a canonical request of style
func getCanonicalRequest(extractedSignedHeaders http.Header, payload, queryStr, urlPath, method string) string {
	rawQuery := strings.ReplaceAll(queryStr, "+", "%20")
	encodedPath := s3utils.EncodePath(urlPath)
	canonicalRequest := strings.Join([]string{
		method,
		encodedPath,
		rawQuery,
		getCanonicalHeaders(extractedSignedHeaders),
		getSignedHeaders(extractedSignedHeaders),
		payload,
	}, "\n")
	return canonicalRequest
}

if flags.Changed(flagAvailability) {
	switch a := swarm.NodeAvailability(strings.ToLower(opts.availability)); a {
	case swarm.NodeAvailabilityActive, swarm.NodeAvailabilityPause, swarm.NodeAvailabilityDrain:
		availability = a
	default:
		return fmt.Errorf("invalid availability %q, only active, pause and drain are supported", opts.availability)
	}
}

type Quota interface {
	// Available judges whether the given request fits within the quota.
	Available(req any) bool
	// Cost computes the charge against the quota for a given request.
	Cost(req any) int
	// Remaining is the amount of charge left for the quota.
	Remaining() int64
}

type passthroughQuota struct{}

func (*passthroughQuota) Available(any) bool { return true }
func (*passthroughQuota) Cost(any) int       { return 0 }
func (*passthroughQuota) Remaining() int64   { return 1 }

switch event.Type {
case watch.Error:
	// keep waiting in the event we see an error - we expect the watch to be closed by
	// the server if the error is unrecoverable.
	err := apierrors.FromObject(event.Object)
	fmt.Fprintf(w.errOut, "error: An error occurred while waiting for the object to be deleted: %v", err)
	return false, nil
case watch.Deleted:
	return true, nil
default:
	return false, nil
}

if attach {
	// ctx should not be cancellable here, as this would kill the stream to the container
	// and we want to keep the stream open until the process in the container exits or until
	// the user forcefully terminates the CLI.
	closeFn, err := attachContainer(ctx, dockerCli, containerID, &errCh, config, client.ContainerAttachOptions{
		Stream:     true,
		Stdin:      config.AttachStdin,
		Stdout:     config.AttachStdout,
		Stderr:     config.AttachStderr,
		DetachKeys: detachKeys,
	})
	if err != nil {
		return err
	}
	defer closeFn()
}

if len(pruneFilters) > 0 {
	// TODO remove fixed list of filters, and print all filters instead,
	// because the list of filters that is supported by the engine may evolve over time.
	for _, name := range []string{"label", "label!", "until"} {
		for v := range pruneFilters[name] {
			filters = append(filters, name+"="+v)
		}
	}
	sort.Slice(filters, func(i, j int) bool {
		return sortorder.NaturalLess(filters[i], filters[j])
	})
}

if kind == abi.Array || kind == abi.Struct {
	// for composite objects we have to read every address
	// because a write might happen to any subobject.
	racereadrangepc(addr, t.Size_, callerpc, pc)
} else {
	// for non-composite objects we can read just the start
	// address, as any write must write the first byte.
	racereadpc(addr, callerpc, pc)
}

if kind == abi.Array || kind == abi.Struct {
	// for composite objects we have to write every address
	// because a write might happen to any subobject.
	racewriterangepc(addr, t.Size_, callerpc, pc)
} else {
	// for non-composite objects we can write just the start
	// address, as any write must write the first byte.
	racewritepc(addr, callerpc, pc)
}

switch {
case apierrors.IsUnauthorized(err):
	// SSL terminating proxies may report this error instead of the master
	m.serverHealth = true
case apierrors.IsUnexpectedServerError(err):
	// generally indicates a proxy or other load balancer problem, rather than a problem coming
	// from the master
	m.serverHealth = false
default:
	// Identify known errors that could be expected for a cert request that
	// indicate everything is working normally
	m.serverHealth = apierrors.IsNotFound(err) || apierrors.IsForbidden(err)
}

for node := range nodes {
	incoming := false
	// iterate over all remaining edges
	for edge := range graph {
		// if there's any edge to the node we care about, it's not a root
		if edge.to == node {
			incoming = true
			break
		}
	}
	// if there are no incoming edges, remove from the set of remaining nodes and add to our results
	if !incoming {
		delete(nodes, node)
		roots = append(roots, node)
	}
}

if !podsExist {
	// This pod may be the first pod in a series that have affinity to themselves. In order
	// to not leave such pods in pending state forever, we check that if no other pod
	// in the cluster matches the namespace and selector of this pod, the pod matches
	// its own terms, and the node has all the requested topologies, then we allow the pod
	// to pass the affinity check.
	if len(state.affinityCounts) == 0 && podMatchesAllAffinityTerms(state.podInfo.GetRequiredAffinityTerms(), state.podInfo.GetPod()) {
		return true
	}
	return false
}

if !podsDifferSemantically(existing, ref) {
	// this is not an update
	// Only check reconcile when it is not an update, because if the pod is going to
	// be updated, an extra reconcile is unnecessary
	if !reflect.DeepEqual(existing.Status, ref.Status) {
		// Pod with changed pod status needs reconcile, because kubelet should
		// be the source of truth of pod status.
		existing.Status = ref.Status
		needReconcile = true
	}
	return
}

if len(updatedFailedQuotas) == 0 {
	// all the updates succeeded.  At this point, anything with the default deny error was just waiting to
	// get a successful update, so we can mark and notify
	for _, admissionAttribute := range admissionAttributes {
		if IsDefaultDeny(admissionAttribute.result) {
			admissionAttribute.result = nil
		}
	}
	return
}

if re.Raw == nil {
	// TODO: this is to support legacy behavior of JSONPrinter and YAMLPrinter, which
	// expect to call json.Marshal on arbitrary versioned objects (even those not in
	// the scheme). pkg/kubectl/resource#AsVersionedObjects and its interaction with
	// kubectl get on objects not in the scheme needs to be updated to ensure that the
	// objects that are not part of the scheme are correctly put into the right form.
	if re.Object != nil {
		return json.Marshal(re.Object)
	}
	return []byte("null"), nil
}

if !u.initialized {
	if nodeCount == 0 {
		// Two possibilities: either the orchestrator hasn't created
		// the tasks yet, or the service doesn't meet constraints for
		// any node. Either way, we wait.
		u.progressOut.WriteProgress(progress.Progress{
			ID:     "overall progress",
			Action: "waiting for new tasks",
		})
		return false, nil
	}

	writeOverallProgress(u.progressOut, 0, nodeCount, rollback)
	u.initialized = true
}

if restartPolicy != nil {
	// TODO: log or error if both "service.restart" and "service.deploy.restartpolicy" are set.
	return &swarm.RestartPolicy{
		Condition:   swarm.RestartPolicyCondition(restartPolicy.Condition),
		Delay:       composetypes.ConvertDurationPtr(restartPolicy.Delay),
		MaxAttempts: restartPolicy.MaxAttempts,
		Window:      composetypes.ConvertDurationPtr(restartPolicy.Window),
	}, nil
}

for registryHostname := range c.CredentialHelpers {
	newAuth, err := c.GetAuthConfig(registryHostname)
	if err != nil {
		// TODO(thaJeztah): use context-logger, so that this output can be suppressed (in tests).
		logrus.WithError(err).Warnf("Failed to get credentials for registry: %s", registryHostname)
		continue
	}
	auths[registryHostname] = newAuth
}

// Use it when you need to have access to all samples without chunk encoding abstraction e.g promQL.
type Queryable interface {
	// Querier returns a new Querier on the storage.
	Querier(mint, maxt int64) (Querier, error)
}

// A MockQueryable is used for testing purposes so that a mock Querier can be used.
type MockQueryable struct {
	MockQuerier Querier
}

func (q *MockQueryable) Querier(int64, int64) (Querier, error) {
	return q.MockQuerier, nil
}

switch template {
case "", formatter.JSONFormat, formatter.JSONFormatKey:
	// No format (default) and full JSON output need server-side info.
	return true
default:
	if placeHolders.FindString(template) == "" {
		// The template does not contain formatting fields; assume we
		// need server-side information to render it, and return early.
		return true
	}
}

for i, tpar := range tparams {
	// Ensure that we have a (possibly implicit) interface as type bound (go.dev/issue/51048).
	tpar.iface()
	// The type parameter bound is parameterized with the same type parameters
	// as the instantiated type; before we can use it for bounds checking we
	// need to instantiate it with the type arguments with which we instantiated
	// the parameterized type.
	bound := check.subst(pos, tpar.bound, smap, nil, ctxt)
	var cause string
	if !check.implements(targs[i], bound, true, &cause) {
		return i, errors.New(cause)
	}
}

if podChanged {
	// if the labels and pod changed, all services need to be updated
	services = services.Union(oldServices)
} else {
	// if only the labels changed, services not common to both the new
	// and old service set (the disjuntive union) need to be updated
	services = services.Difference(oldServices).Union(oldServices.Difference(services))
}

for status := range statuses {
	// ComponentStatus resources currently (v1.14) do not support labeling, however the filtering is executed
	// nonetheless in case the request contains Label or Field selectors (which will effectively filter out
	// all of the results and return an empty response).
	if matched := matchesPredicate(status, &pred); matched {
		reply = append(reply, status)
	}
}

if leaderMigrator != nil {
	// If leader migration is enabled, we should start only non-migrated controllers
	//  for the main lock.
	initializers = filterInitializers(controllerInitializers, leaderMigrator.FilterFunc, leadermigration.ControllerNonMigrated)
	klog.Info("leader migration: starting main controllers.")
	// Signal the main lock is acquired, and thus migration lock is ready to attempt.
	close(leaderMigrator.MigrationReady)
}

for _, constraint := range constraints {
	switch constraint {
	case NoSet, NoUnset:
		// These constraints don't apply to non-pointer structs
		// as they can't be unset. This should be caught at generation time.
		continue
	case NoModify:
		// Non-pointer structs are always considered "set". Therefore, any
		// change detected by validation ratcheting is a modification.
		// The deep equality check is redundant and has been removed.
		errs = append(errs, field.Invalid(fldPath, nil, "field cannot be modified once set").WithOrigin("update"))
	}
}

if cmpm.IsMigrationEnabledForPlugin(provisioner) {
	// Remove in-tree delete finalizer on the PV as migration is enabled.
	if slices.Contains(outFinalizers, storagehelpers.PVDeletionInTreeProtectionFinalizer) {
		outFinalizers = slice.RemoveString(outFinalizers, storagehelpers.PVDeletionInTreeProtectionFinalizer, nil)
		modified = true
	}
	return outFinalizers, modified
}

if len(item.identity.Namespace) == 0 && namespaced {
	// item is a cluster-scoped object referring to a namespace-scoped owner, which is not valid.
	// return a marker error, rather than retrying on the lookup failure forever.
	logger.V(2).Info("item is cluster-scoped, but refers to a namespaced owner",
		"item", item.identity,
		"owner", reference,
	)
	return false, nil, namespacedOwnerOfClusterScopedObjectErr
}

if scheduledTime == nil {
	// no unmet start time, return cj,.
	// The only time this should happen is if queue is filled after restart.
	// Otherwise, the queue is always suppose to trigger sync function at the time of
	// the scheduled time, that will give atleast 1 unmet time schedule
	logger.V(4).Info("No unmet start times", "cronjob", klog.KObj(cronJob))
	t := nextScheduleTimeDuration(cronJob, now, sched)
	return t, updateStatus, nil
}

if err == nil {
	// kubeadm doesn't validate the existing certificate key more than this;
	// Basically, if we find a key file with the same path kubeadm thinks those files
	// are equal and doesn't bother writing a new file
	fmt.Printf("[certs] Using the existing %q key\n", kubeadmconstants.ServiceAccountKeyBaseName)
	return nil
} else if !os.IsNotExist(err) {
	return errors.Wrapf(err, "file %s existed but it could not be loaded properly", kubeadmconstants.ServiceAccountPrivateKeyName)
}

switch fileType {
case hostutil.FileTypeBlockDev:
	// local volume plugin does not implement AttachableVolumePlugin interface, so set devicePath to Path in PV spec directly
	return dm.mountLocalBlockDevice(spec, spec.PersistentVolume.Spec.Local.Path, deviceMountPath)
case hostutil.FileTypeDirectory:
	// if the given local volume path is of already filesystem directory, return directly
	return nil
default:
	return fmt.Errorf("only directory and block device are supported")
}

if d.warnl != nil {
	// There should be very little warnings (fingers crossed!),
	// but this will typically be unrecognized formats.
	// To be able to possibly get rid of these warnings,
	// we need to know what images are causing them.
	warnf = func(format string, args ...any) {
		format = fmt.Sprintf("%q: %s: ", filename, format)
		d.warnl.Logf(format, args...)
	}
}

// channelHandlers manages the series of channels returned by various processes.
// It allows us to wait for those processes to terminate before exiting the
// program.
type channelHandlers struct {
	handlers []chan struct{}
	mu       sync.RWMutex
}

// Adds a channel to the list of handlers. We wait for all handlers to terminate
// gracefully on shutdown.
func (h *channelHandlers) add(ch chan struct{}) {
	h.mu.Lock()
	h.handlers = append(h.handlers, ch)
	h.mu.Unlock()
}

if err != nil {
	// Checking for removed Kubernetes API error so can provide a more informative error message to the user
	// Ref: https://github.com/helm/helm/issues/7219
	if strings.Contains(err.Error(), "unable to recognize \"\": no matches for kind") {
		return upgradedRelease, fmt.Errorf("current release manifest contains removed kubernetes api(s) for this "+
			"kubernetes version and it is therefore unable to build the kubernetes "+
			"objects for performing the diff. error from kubernetes: %w", err)
	}
	return upgradedRelease, fmt.Errorf("unable to build kubernetes objects from current release manifest: %w", err)
}

type Lease struct {
	ID           LeaseID
	ttl          int64 // time to live of the lease in seconds
	remainingTTL int64 // remaining time to live in seconds, if zero valued it is considered unset and the full ttl should be used
	// expiryMu protects concurrent accesses to expiry
	expiryMu sync.RWMutex
	// expiry is time when lease should expire. no expiration when expiry.IsZero() is true
	expiry time.Time

	// mu protects concurrent accesses to itemSet
	mu      sync.RWMutex
	itemSet map[LeaseItem]struct{}
	revokec chan struct{}
}

type AlertState int

const (
	// StateUnknown is the state of an alert that has not yet been evaluated.
	StateUnknown AlertState = iota
	// StateInactive is the state of an alert that is neither firing nor pending.
	StateInactive
	// StatePending is the state of an alert that has been active for less than
	// the configured threshold duration.
	StatePending
	// StateFiring is the state of an alert that has been active for longer than
	// the configured threshold duration.
	StateFiring
)

type Ordering uint8

const (
	// OrderByValueAsc orders results ascending by Value. This matches the
	// natural index order and is the zero value of Ordering.
	OrderByValueAsc Ordering = iota
	// OrderByValueDesc orders results descending by Value.
	OrderByValueDesc
	// OrderByScoreDesc orders results descending by Score, breaking ties
	// ascending by Value for determinism.
	OrderByScoreDesc
)

select {
case <-wb.donec:
	// watchProxyStream will hold watchRanges global mutex lock all the time if client failed to cancel etcd watchers.
	// and it will cause the watch proxy to not work.
	// please see pr https://github.com/etcd-io/etcd/pull/12030 to get more detail info.
case <-time.After(time.Second):
	wb.lg.Error("failed to cancel etcd watcher")
}

if check.errpos != nil {
	// If we have an internal error and the errpos override is set, use it to
	// augment our error positioning.
	// TODO(rFindley) we may also want to augment the error message and refer
	// to the position (pos) in the original expression.
	span := spanOf(check.errpos)
	e.Pos = span.pos
	e.go116start = span.start
	e.go116end = span.end
}

if merge {
	// deep copying the cvals as there are cases where pointers can end
	// up in the cvals when they are copied onto b in ways that break things.
	cvals = deepCopyMap(cvals)
	c.Values = util.MergeTables(cvals, b)
} else {
	// Trimming the nil values from cvals is needed for backwards compatibility.
	// Previously, the b value had been populated with cvals along with some
	// overrides. This caused the coalescing functionality to remove the
	// nil/null values. This trimming is for backwards compat.
	cvals = trimNilValues(cvals)
	c.Values = util.CoalesceTables(cvals, b)
}

for l := range affected {
	i++
	process(l)

	// From time to time we want some readers to go through and read their postings.
	// It takes around 50ms to process a 1K series batch, and 120ms to process a 10K series batch (local benchmarks on an M3).
	// Note that a read query will most likely want to read multiple postings lists, say 5, 10 or 20 (depending on the number of matchers)
	// And that read query will most likely evaluate only one of those matchers before we unpause here, so we want to pause often.
	if i%512 == 0 {
		p.unlockWaitAndLockAgain()
	}
}

if !found {
	if pc != nil {
		// Content adapter resources have explicit site matrix config; respect all dimensions.
		found = pc.MatchSiteVectorCoarse(siteVector)
	} else if p.fi != nil {
		// File-based resources: exclude the language dimension in the coarse match.
		// The typical setup is to provide translated content files but one resource (e.g. an image) that is shared between the translations.
		// To give all the languages a full set, we ignore that dimension for this last fallback check.
		found = p.fi.Meta().MatchSiteVectorCoarseExcludeLanguage(siteVector)
	}
}

const (
	EventTypeDelete = mvccpb.Event_DELETE
	EventTypePut    = mvccpb.Event_PUT

	closeSendErrTimeout = 250 * time.Millisecond

	// AutoWatchID is the watcher ID passed in WatchStream.Watch when no
	// user-provided ID is available. If pass, an ID will automatically be assigned.
	AutoWatchID = 0

	// InvalidWatchID represents an invalid watch ID and prevents duplication with an existing watch.
	InvalidWatchID = -1

	watcherStreamBufWarningInterval  = 5 * time.Second
	watcherStreamBufWarningThreshold = 100 * time.Millisecond
)

// Events can be passed to external systems via AMQP or similar message buses.
// Treat these events as DTOs: changes must be backward compatible.
type SignUpStarted struct {
	Timestamp time.Time `json:"timestamp"`
	Email     string    `json:"email"`
	Code      string    `json:"code"`
}

type SignUpCompleted struct {
	Timestamp time.Time `json:"timestamp"`
	Name      string    `json:"name"`
	Email     string    `json:"email"`
}

if s.Spec.Mode.GlobalJob != nil {
	// for global jobs, we need to do a little math. desired tasks are only
	// the tasks that have not yet actually reached the Completed state.
	// Completed tasks have reached the completed state. the TOTAL number
	// of tasks to run is the sum of the tasks desired to still complete,
	// and the tasks actually completed.
	return fmt.Sprintf(
		"%d/%d (%d/%d completed)",
		running, desired, completed, desired+completed,
	)
}

if editMode == ApplyEditMode {
	fmt.Fprint(w, `# Please edit the 'last-applied-configuration' annotations below.
# Lines beginning with a '#' will be ignored, and an empty file will abort the edit.
#
`)
} else {
	fmt.Fprint(w, `# Please edit the object below. Lines beginning with a '#' will be ignored,
# and an empty file will abort the edit. If an error occurs while saving this file will be
# reopened with the relevant failures.
#
`)
}
